<div class="popup-over" id="popupOver">
    <div class="popup-box">
        <h2>✔ ✔</h2>
        <p>Richiesta inviata con successo</p>
        <button class="close" id="closePopup">[ Chiudi ]</button>
    </div>
</div>

    <!-- Card principale -->
    <div class="card">
        <h1>⚀ AI Code</h1>
        <span class="s-sub">— cyberpunk emporium —</span>

        <form id="contactForm">
            <div class="grid">
                <div class="input-group">
                    <label for="name">[ N_ ]</label>
                    <input type="text" id="name" placeholder="> nome oper" required>
                </div>
                <div class="input-group">
                    <label for="email">[ @ ]</label>
                    <input type="email" id="email" placeholder="> link com" required>
                </div>
                <div class="input-group">
                    <label for="message">[ mess_ ]</label>
                    <textarea id="message" placeholder="> scrivi richi..." required></textarea>
                </div>
                <button type="submit" id="inBtn">◉ invia</button>
            </div>
       form>

        <div class="footer">
            <span>✧ 202° AI • proto •</span><br>
            <a href="#">[ accesso deep ]</a>
        </div>
    </div>

    <script>
    // JS per popup e modulo
    function() {
        // Previsti errori e invio
        document.getElementById('contactForm'). addEventListener('submit', function(e) {
            e.preventDefault(); // blocco invio trad
            // Validazione base
            const name = document.getElementById('name);
            const email = document.getElementById('email);
            const message = document.getElementById('message);
            if (name.value.trim() === '' || email.value.trim() === '' || message.value.trim() === '' ) {
                alert('c' da compire');
                return;
            }
            // Mostra popup
            document.getElementById('popupOver'). classList.add('show');
            // Reset eventuale
            // Non serve per pulire
        });

        // Chiudi popup
        document.getElementById('closePopup'). addEventListener('click', function() {
            document.getElementById('popupOver'). classList.remove('show');
        });

        // Chiudi overlay se clicchi fuori
        document.getElementById('popupOver'). addEventListener('click', function(e) {
            if (e.target.id === 'popupOver') {
                document.getElementById('popupOver'). classList.remove('show');
            }
        });
    // Prev alert per compire
    </script>
    </script>
